var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"한낱 미물 주제에 제법이구나.","JPN":"微物の分際でやるではないか。","ENG":"Not bad, for a mere vermin.","TWN":"一介微不足道的存在，倒也有幾分本事。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"하지만 소용없을 거다. 왕께서 가호하시니 이 육신이 무너지는 일은 없으리라.","JPN":"だが無駄だ。王の加護がある限りこの肉体が壊れることはない。","ENG":"But it won't matter. With the queen's blessing, this flesh will not fall.","TWN":"不過沒用的。王的加護在此，這具肉身不可能崩壞。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"클리파에 물든 현실이 네놈에겐 제법 유리한 환경인 모양이군.","JPN":"クリファに染まった現実があんたには随分有利なようね。","ENG":"A reality steeped in Qlipha does seem to favor you.","TWN":"被逆卡巴拉污染的現實，對你而言似乎是相當有利的環境呢。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"이 아스널 윙은 얼터니움으로 급조된 레플리카… 성능은 엇비슷하지만 쓸 수 있는 시간에 제한이 있어.","JPN":"このアーセナルウイングはオルタニウムで作った間に合わせのレプリカ……性能はほぼ同じとはいえ、使える時間に制限がある。","ENG":"The Arsenal Wings are a hastily made replica powered by Alternium... Comparable performance, but with a strict time limit.","TWN":"這具軍火之翼是用永恆之金臨時製作的複製品……性能相差無幾，但可用時間有限。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":null,"R":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"단시간에 끝내지 못하면, 이쪽이 압도적으로 불리해진다.","JPN":"短時間で終わらせないと、こっちが圧倒的に不利になる。","ENG":"If I can't finish this quickly, I'll be at a severe disadvantage.","TWN":"若無法在短時間內結束戰鬥，局勢就會對我們極為不利。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":null,"R":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"죄송해요.","JPN":"すいません。","ENG":"I'm sorry.","TWN":"對不起。"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"저를 지키느라… 제대로 싸우기 힘드신 거죠?","JPN":"私を守っているせいで……上手く戦えないんですよね。","ENG":"You're having trouble fighting properly because you're protecting me, aren't you?","TWN":"為了保護我……你是不是沒辦法全力戰鬥？"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"…아닙니다.","JPN":"……いいえ。","ENG":"...No.","TWN":"……不是的。"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"저 녀석을 쓰러트리는 건 부차적인 문제일 뿐. 소기의 목적은 이미 달성했으니까요.","JPN":"やつを倒すことは付随的な問題にすぎません。当初の目的はすでに達成しています。","ENG":"Defeating that thing is only a secondary concern. The primary objective has already been achieved.","TWN":"打倒那傢伙只是次要問題。我們的首要目標已經達成了。"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"소기의 목적이라면?","JPN":"当初の目的？","ENG":"The primary objective?","TWN":"首要目標？"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"니콜 프라이머를 무사히 구출하라는, 관리국 지침이 있었거든요.","JPN":"ニコル・プライマーを無事救出してほしいという、管理局の指示がありました。","ENG":"The Administration issued a directive to extract Nicole Primer safely.","TWN":"管理局的指示是務必確保妮可．布萊伊莫的安全。"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"관리국이… 저를 구하라고 했다고요?","JPN":"管理局が……私の救出を？","ENG":"The Administration... ordered my rescue?","TWN":"管理局……下令來救我？"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"네. 그리고 나머지는 후발대가 알아서 해결할 겁니다.","JPN":"はい。そして後のことは後発隊がやってくれるでしょう。","ENG":"Yes. And the rest will be handled by the reinforcements.","TWN":"是的。剩下的就交給後續部隊處理吧。"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"하늘이…","JPN":"空が……","ENG":"The sky...","TWN":"天空……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"…새하얘.","JPN":"……真っ白。","ENG":"...It's completely white.","TWN":"……一片雪白。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"저건… 천사?","JPN":"あれは……天使？","ENG":"Is that... an angel?","TWN":"那是……天使？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_MEMORY","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"뭐지?!","JPN":"何だ！？","ENG":"What?!","TWN":"什麼？！"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"역시 휴먼들이 만든 정책은 신뢰할 게 못 됩니다.","JPN":"やはりヒューマンの作った政策は信頼に値しません。","ENG":"As expected, policies made by humans are never worth trusting.","TWN":"果然，人類制定的政策根本不值得信任。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"치안관리 명목으로 세금은 꼬박꼬박 뜯어가더니, 사이렌만 시끄럽게 울리는 게 전붑니까?","JPN":"治安管理を理由に税金はきっちり取るくせに、サイレンをうるさく鳴らすことしかできないのですか？","ENG":"They take taxes faithfully under the guise of public security, yet all they do is blare sirens?","TWN":"以管理治安為名，稅金倒是一毛不少收，結果只會把警報拉得震天響嗎？"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"귀하의 원자로급 리액터를 가득 충전하려면 도시 단위의 에너지가 필요하다는 건 알고 계신가요?","JPN":"あなたの原子炉級リアクターをフルチャージするためには、都市レベルのエネルギーが要るということはご存知ですか？","ENG":"You do realize that fully charging your reactor would require energy on a citywide scale, correct?","TWN":"你知道要把你的電抗器核心完全充能，需要城市等級的能源嗎？"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"협조해주신 대가로 관리국에서 특별히- 세금은 청구하지 않겠다더군요. 그러니 잘 부탁드립니다.","JPN":"協力していただいたお礼として特別に税金の請求はしないそうですよ。ですから、よろしくお願いしますね。","ENG":"As compensation for your cooperation, the Administration has decided exceptionally not to levy taxes. We appreciate your assistance.","TWN":"作為配合的代價，管理局特別表示—不會向你課稅。所以還請多多關照。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"세상이 망하기 직전까지 돈 타령이라니, 관리국에도 인간미 넘치는 휴먼이 있군요.","JPN":"世界滅亡が目前に迫っているのに金の話とは、管理局にも人間味あふれるヒューマンがいるんですね。","ENG":"Arguing about money right up to the brink of the world's end... Seems the Administration has some humans with humanity left in them.","TWN":"都世界末日前夕了還在談錢，管理局裡倒也挺有人情味的啊。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"이번 일이 끝나면, 직접 그 얼굴을 보면서 얘기하겠습니다.","JPN":"今回の仕事が終わったら、顔を合わせながらお話しましょう。","ENG":"Once this is over, I'll speak to you face-to-face.","TWN":"等這次事件結束，我會親自與你會面聊聊。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그 날개는- 아시모프가 보낸 사도인가?","JPN":"その翼は……アシモフが送った使徒か？","ENG":"Those wings... are you an Apostle sent by Asimov?","TWN":"那對翅膀—是阿西莫夫派來的使徒嗎？"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"사도가 아니라 모범납세자입니다, 이 외래침입종.","JPN":"使徒ではなく模範的納税者です。この侵略的外来種め。","ENG":"Not an Apostle. A model taxpayer, you invasive species.","TWN":"不是使徒，是模範納稅人喔，外來侵入種。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"불쌍한 것. 어설픈 자아를 가진 탓에 복종하는 인형의 본분을 잊고 망가진 모양이구나.","JPN":"哀れな。中途半端な自我を持ったせいで、服従という人形の本質を忘れ壊れてしまったようだな。","ENG":"Pitiable. It seems you forgot the role of an obedient doll because you developed a half-baked ego.","TWN":"可憐的傢伙因為擁有半吊子的自我意識，忘了作為服從機器人的本分，才會變成這副模樣。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"저도 스스로를 기구하다고 생각하는 편입니다만.","JPN":"我ながら自分の生が数奇なものだとは思っていますが。","ENG":"I do consider myself unfortunate.","TWN":"我自己也常覺得命運悲慘。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"휴먼에서 자아도 없는 인형으로 전락한 당신에 비하면, 제 사정이 훨씬 낫군요.","JPN":"ヒューマンより自我すらない人形に成り果てたあなたに比べると、私のほうがずっとマシです。","ENG":"But compared to you, who fell from human to a mindless puppet, my situation is far better.","TWN":"不過，比起你這個從人類淪落成毫無自我的機器人，我的處境好多了。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};